          "type": "object",
          "properties": {
            "category": {
              "type": "string",
              "description": "Always \"problem-list-item\" for this API."
            },
            "patient": {
              "type": "string",
              "description": "Reference to a patient resource the condition is for."
            }
          },
          "required": [
            "patient"
